// settingsLayout merges the player-vs-designer realm decision: designer
// uses the populated Layout; player realm keeps the legacy
// HideTopNav-controlled chrome via PlayTopNav.
func settingsLayout(p SettingsProps) LayoutProps {
	if p.HideTopNav {
		return LayoutProps{
			Title:      "Settings",
			Surface:    "settings",
			BodyClass:  "bx-settings-body",
			HideTopNav: true,
		}
	}
	if p.Layout.BodyClass == "" {
		p.Layout.BodyClass = "bx-settings-body"
	}
	return p.Layout
}

